package ru.rsreu.sovynhik.pract_03;import ru.rsreu.sovynhik.pract_03.config.Constants;import ru.rsreu.sovynhik.pract_03.model.*;import ru.rsreu.sovynhik.pract_03.repository.*;import ru.rsreu.sovynhik.pract_03.service.*;import ru.rsreu.sovynhik.pract_03.ui.ConsoleUI;import java.util.Scanner;/** * Главный класс приложения системы дискреционного управления доступом (DAC). * Выполняет инициализацию компонентов, запрашивает у пользователя параметры * и запускает консольный интерфейс. */public class SecuritySystemApp {    /**     * Точка входа в приложение.     * Запрашивает количество пользователей и объектов, инициализирует репозитории,     * сервисы и запускает пользовательский интерфейс.     *     * @param args аргументы командной строки (не используются)     */    public static void main(String[] args) {        Scanner scanner = new Scanner(System.in);        System.out.print("Введите количество пользователей: ");        int userCount = Integer.parseInt(scanner.nextLine());        System.out.print("Введите количество объектов: ");        int objectCount = Integer.parseInt(scanner.nextLine());        UserRepository userRepository = initializeUsers(userCount);        ObjectRepository objectRepository = initializeObjects(objectCount);        AccessMatrixRepository accessMatrixRepository = new AccessMatrixRepository();        AccessMatrixService accessMatrixService = new AccessMatrixService(                accessMatrixRepository, userRepository, objectRepository);        accessMatrixService.initializeMatrix();        AuthenticationService authenticationService = new AuthenticationService(userRepository);        AuthorizationService authorizationService = new AuthorizationService(accessMatrixService);        ConsoleUI ui = new ConsoleUI(authenticationService, accessMatrixService, authorizationService);        ui.start();    }    /**     * Инициализирует репозиторий пользователей.     * Создает указанное количество пользователей, включая одного администратора     * с именем {@link Constants#ADMIN_NAME} и остальных обычных пользователей     * с именами вида {@link Constants#USER_PREFIX} + номер.     *     * @param count общее количество пользователей (включая администратора)     * @return заполненный репозиторий пользователей     */    private static UserRepository initializeUsers(int count) {        UserRepository repository = new UserRepository();        repository.addUser(new User(Constants.ADMIN_NAME, true));        for (int i = 1; i < count; i++) {            repository.addUser(new User(Constants.USER_PREFIX + i, false));        }        return repository;    }    /**     * Инициализирует репозиторий системных объектов.     * Создает указанное количество объектов с именами вида     * {@link Constants#OBJECT_PREFIX} + номер.     *     * @param count количество объектов     * @return заполненный репозиторий объектов     */    private static ObjectRepository initializeObjects(int count) {        ObjectRepository repository = new ObjectRepository();        for (int i = 1; i <= count; i++) {            repository.addObject(new SystemObject(i));        }        return repository;    }}